member.example:
Bind the Collider enabled property using a serialized binder field — the target Collider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ColliderEnabledBinder _enabled;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _enabled;
    }


Bind the Collider enabled property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Collider _collider;
        
        private ColliderEnabledBinder Enabled =>
            new(_collider);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _enabled;
    }
